#!/usr/bin/env python3
"""
William Hill FAST PROD15 V18 — ONE FILE

Runs the validated V17 logic across 15 fixtures, writes only to the isolated
candidate JSON, then runs the strict validator.

It does NOT replace:
  football/data/williamhill_worldcup_props.json

Candidate output:
  football/data/williamhill_worldcup_props_FAST_PROD15_V18_CANDIDATE.json
"""

from __future__ import annotations

import base64
import sys
from pathlib import Path


SCRAPER_SOURCE_B64 = ''
VALIDATOR_SOURCE_B64 = ''


def run_embedded(source_b64: str, label: str) -> int:
    source = base64.b64decode(source_b64.encode("ascii")).decode("utf-8")
    namespace = {
        "__name__": f"_embedded_{label}",
        "__file__": str(Path(__file__).resolve()),
        "__package__": None,
    }
    exec(compile(source, str(Path(__file__).resolve()), "exec"), namespace)

    main_fn = namespace.get("main")
    if not callable(main_fn):
        print(f"ERROR: embedded {label} has no main() function")
        return 2

    old_argv = sys.argv[:]
    try:
        sys.argv = [str(Path(__file__).resolve())]
        result = main_fn()
        return int(result or 0)
    finally:
        sys.argv = old_argv


def main() -> int:
    print("=" * 72)
    print("William Hill FAST PROD15 V18 — ONE FILE")
    print("Production JSON will NOT be replaced")
    print("=" * 72)
    print()

    scrape_code = run_embedded(SCRAPER_SOURCE_B64, "scraper")
    if scrape_code != 0:
        print()
        print(f"SCRAPER FAILED with exit code {scrape_code}")
        print("Existing production remains untouched.")
        return scrape_code

    print()
    print("=" * 72)
    print("Running strict candidate validator")
    print("=" * 72)
    print()

    validation_code = run_embedded(VALIDATOR_SOURCE_B64, "validator")
    if validation_code != 0:
        print()
        print(f"VALIDATION FAILED with exit code {validation_code}")
        print("Existing production remains untouched.")
        return validation_code

    print()
    print("=" * 72)
    print("PASS — V18 candidate completed and validated")
    print("Existing production still remains untouched")
    print("=" * 72)
    return 0


if __name__ == "__main__":
    raise SystemExit(main())
